using NewSmartAIFactory.CompanyApi.Models;using Npgsql;
namespace NewSmartAIFactory.CompanyApi.Services;
public sealed class ReportGenerationService
{
 private readonly string _connectionString;private readonly PostgresFactoryWriteService _writer;public ReportGenerationService(IConfiguration config,PostgresFactoryWriteService writer){_connectionString=config.GetConnectionString("Postgres")??throw new InvalidOperationException("Connection string 'Postgres' is missing.");_writer=writer;}
 public async Task<string> GenerateAsync(GenerateReportRequest request,CancellationToken token){var done=new List<string>();var doing=new List<string>();var blocked=new List<string>();var decisions=new List<string>();await using var c=new NpgsqlConnection(_connectionString);await c.OpenAsync(token);await using(var cmd=new NpgsqlCommand("select title,status from tasks where project_id=@project order by id",c)){cmd.Parameters.AddWithValue("project",request.ProjectId);await using var r=await cmd.ExecuteReaderAsync(token);while(await r.ReadAsync(token)){var title=r.GetString(0);switch(r.GetString(1)){case"Done":done.Add(title);break;case"Blocked":blocked.Add(title);break;default:doing.Add(title);break;}}}await using(var cmd=new NpgsqlCommand("select title,status from approval_requests where project_id=@project and status in ('Pending','NeedsMoreInfo','Deferred') order by created_at_utc",c)){cmd.Parameters.AddWithValue("project",request.ProjectId);await using var r=await cmd.ExecuteReaderAsync(token);while(await r.ReadAsync(token))decisions.Add($"{r.GetString(0)} ({r.GetString(1)})");}var total=done.Count+doing.Count+blocked.Count;var progress=total==0?0:(int)Math.Round(done.Count*100d/total);var summary=$"{done.Count} done, {doing.Count} in progress, {blocked.Count} blocked, {decisions.Count} approvals need attention.";return await _writer.CreateReportAsync(new CreateReportRequest(request.ProjectId,request.ReportType,request.Period,progress,done,doing,blocked,decisions,request.PublishedBy??"PM",summary),token);}
}
